--- a/packages/ui/src/engine/pixel-characters.ts
+++ b/packages/ui/src/engine/pixel-characters.ts
@@ -715,6 +715,122 @@
-// ─── Draw pixel art sprite with outlines and shading ─────────────
+// ─── Decorative props pixel art drawing functions ─────────────
+
+function drawTapestry(ctx: CanvasRenderingContext2D, x: number, y: number, color: string) {
+  // 8x16 tapestry with simple pattern
+  ctx.fillStyle = color;
+  ctx.fillRect(x, y, 8, 16);
+  ctx.fillStyle = '#000000';
+  // vertical stripes
+  for (let i = 1; i < 8; i += 2) {
+    ctx.fillRect(x + i, y, 1, 16);
+  }
+  // fringe bottom
+  ctx.fillRect(x, y + 15, 8, 1);
+}
+
+function drawWallShield(ctx: CanvasRenderingContext2D, x: number, y: number) {
+  // 12x16 shield with emblem
+  ctx.fillStyle = '#6b4c3b'; // wood base
+  ctx.fillRect(x, y, 12, 16);
+  ctx.fillStyle = '#bfbfbf'; // metal rim
+  ctx.fillRect(x, y, 12, 2);
+  ctx.fillRect(x, y + 14, 12, 2);
+  ctx.fillRect(x, y, 2, 16);
+  ctx.fillRect(x + 10, y, 2, 16);
+  // emblem center
+  ctx.fillStyle = '#d22f27';
+  ctx.beginPath();
+  ctx.moveTo(x + 6, y + 4);
+  ctx.lineTo(x + 9, y + 12);
+  ctx.lineTo(x + 3, y + 12);
+  ctx.closePath();
+  ctx.fill();
+}
+
+function drawCandelabra(ctx: CanvasRenderingContext2D, x: number, y: number) {
+  // 8x16 candelabra with 3 candles
+  ctx.fillStyle = '#654321'; // base
+  ctx.fillRect(x + 3, y + 10, 2, 6);
+  ctx.fillRect(x + 1, y + 12, 6, 2);
+  ctx.fillStyle = '#ffffcc'; // candles
+  ctx.fillRect(x + 1, y + 4, 2, 6);
+  ctx.fillRect(x + 3, y + 2, 2, 8);
+  ctx.fillRect(x + 5, y + 4, 2, 6);
+  ctx.fillStyle = '#ffdd55'; // flames
+  ctx.beginPath();
+  ctx.ellipse(x + 2, y + 3, 1, 2, 0, 0, 2 * Math.PI);
+  ctx.fill();
+  ctx.beginPath();
+  ctx.ellipse(x + 4, y + 1, 1, 2, 0, 0, 2 * Math.PI);
+  ctx.fill();
+  ctx.beginPath();
+  ctx.ellipse(x + 6, y + 3, 1, 2, 0, 0, 2 * Math.PI);
+  ctx.fill();
+}
+
+function drawBarrel(ctx: CanvasRenderingContext2D, x: number, y: number) {
+  // 12x12 barrel
+  ctx.fillStyle = '#8b5a2b'; // wood
+  ctx.fillRect(x, y, 12, 12);
+  ctx.strokeStyle = '#5a3a1a'; // bands
+  ctx.lineWidth = 2;
+  ctx.beginPath();
+  ctx.moveTo(x, y + 3);
+  ctx.lineTo(x + 12, y + 3);
+  ctx.moveTo(x, y + 9);
+  ctx.lineTo(x + 12, y + 9);
+  ctx.stroke();
+  ctx.lineWidth = 1;
+}
+
+function drawCrate(ctx: CanvasRenderingContext2D, x: number, y: number) {
+  // 12x12 crate
+  ctx.fillStyle = '#c2a476';
+  ctx.fillRect(x, y, 12, 12);
+  ctx.strokeStyle = '#8b6b3a';
+  ctx.lineWidth = 1;
+  // vertical planks
+  ctx.beginPath();
+  ctx.moveTo(x + 4, y);
+  ctx.lineTo(x + 4, y + 12);
+  ctx.moveTo(x + 8, y);
+  ctx.lineTo(x + 8, y + 12);
+  // horizontal planks
+  ctx.moveTo(x, y + 4);
+  ctx.lineTo(x + 12, y + 4);
+  ctx.moveTo(x, y + 8);
+  ctx.lineTo(x + 12, y + 8);
+  ctx.stroke();
+}
+
+function drawRug(ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, color: string) {
+  // Rug with border and pattern, min 8x8
+  ctx.fillStyle = color;
+  ctx.fillRect(x, y, w, h);
+  ctx.strokeStyle = '#000000';
+  ctx.lineWidth = 1;
+  ctx.strokeRect(x, y, w, h);
+  // simple diamond pattern inside
+  ctx.fillStyle = '#333333';
+  for (let i = 2; i < w - 2; i += 4) {
+    for (let j = 2; j < h - 2; j += 4) {
+      ctx.beginPath();
+      ctx.moveTo(x + i, y + j - 1);
+      ctx.lineTo(x + i + 1, y + j);
+      ctx.lineTo(x + i, y + j + 1);
+      ctx.lineTo(x + i - 1, y + j);
+      ctx.closePath();
+      ctx.fill();
+    }
+  }
+}
+
+// ─── Draw room with decorations ─────────────
+
+function drawRoom(ctx: CanvasRenderingContext2D, roomType: string, x: number, y: number, scale: number) {
+  // existing room drawing code assumed here
+
+  // Add props per room theme
+  switch (roomType) {
+    case 'workshop':
+      drawBarrel(ctx, x + 10, y + 20);
+      drawCrate(ctx, x + 30, y + 22);
+      drawBarrel(ctx, x + 50, y + 18);
+      drawCrate(ctx, x + 70, y + 24);
+      break;
+    case 'library':
+      // extra bookshelves (reuse existing bookshelf drawing assumed)
+      // add tapestries and rugs
+      drawTapestry(ctx, x + 12, y + 10, '#8b0000');
+      drawTapestry(ctx, x + 60, y + 10, '#004080');
+      drawRug(ctx, x + 20, y + 40, 40, 12, '#a0522d');
+      drawRug(ctx, x + 70, y + 42, 30, 10, '#6a5acd');
+      break;
+    case 'war-room':
+      drawWallShield(ctx, x + 15, y + 12);
+      drawWallShield(ctx, x + 45, y + 14);
+      drawTapestry(ctx, x + 30, y + 10, '#800000');
+      drawCandelabra(ctx, x + 60, y + 20);
+      break;
+    default:
+      // generic decorations
+      drawRug(ctx, x + 10, y + 30, 50, 10, '#556b2f');
+      drawCandelabra(ctx, x + 70, y + 20);
+      break;
+  }
+}
+
